class Solution:
    def asteroidCollision(self, asteroids):
        arr = list(asteroids)
        changed = True
        while changed:
            changed = False
            for i in range(len(arr) - 1):
                if arr[i] > 0 and arr[i + 1] < 0:
                    a, b = arr[i], -arr[i + 1]
                    if a > b:
                        del arr[i + 1]
                    elif a < b:
                        del arr[i]
                    else:
                        del arr[i + 1]
                        del arr[i]
                    changed = True
                    break
        return arr

